exercises.description:
Create a FastAPI app with:
1. A GET endpoint at /greet/{name} that returns {'greeting': 'Hello, {name}!'}
2. A POST endpoint at /greet that accepts a JSON body with 'name' (str) and 'language' (str, default 'en') and returns the greeting. If language is 'es', return 'Hola, {name}!'; if 'fr', return 'Bonjour, {name}!'; otherwise return 'Hello, {name}!'.

exercises.solution:
from fastapi import FastAPI
from pydantic import BaseModel

app = FastAPI()

class GreetRequest(BaseModel):
    name: str
    language: str = "en"

@app.get("/greet/{name}")
def greet_simple(name: str):
    return {"greeting": f"Hello, {name}!"}

@app.post("/greet")
def greet_multilingual(body: GreetRequest):
    greetings = {"en": "Hello", "es": "Hola", "fr": "Bonjour"}
    word = greetings.get(body.language, "Hello")
    return {"greeting": f"{word}, {body.name}!"}

